    <div> <script>
// YouTube Iframe Autoplay Script
// This script adds autoplay functionality to YouTube iframes when clicking on YouTube links

(function() {
    'use strict';
    
    // Function to extract YouTube video ID from URL
    function getYouTubeVideoId(url) {
        const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|&v=)([^#&?]*).*/;
        const match = url.match(regExp);
        return (match && match[2].length === 11) ? match[2] : null;
    }
    
    // Function to add autoplay to YouTube iframe
    function addAutoplayToIframe(iframe) {
        if (!iframe || iframe.tagName !== 'IFRAME') {
            console.warn('Element is not an iframe');
            return false;
        }
        
        const src = iframe.getAttribute('src');
        if (!src || !src.includes('youtube.com/embed/')) {
            console.warn('Not a YouTube embed iframe');
            return false;
        }
        
        // Parse the URL to add autoplay parameters
        let newSrc = src;
        
        // Add autoplay=1 and mute=1 if not already present
        if (!newSrc.includes('autoplay=')) {
            newSrc += (newSrc.includes('?') ? '&' : '?') + 'autoplay=1';
        }
    /*    
        if (!newSrc.includes('mute=')) {
            newSrc += '&mute=1';
        }
        */
        // Update the iframe src
        iframe.setAttribute('src', newSrc);
        
        // Ensure autoplay is in the allow attribute
        let allow = iframe.getAttribute('allow') || '';
        if (!allow.includes('autoplay')) {
            allow = allow ? allow + '; autoplay' : 'autoplay';
            iframe.setAttribute('allow', allow);
        }
        
        console.log('Autoplay added to YouTube iframe');
        return true;
    }
    
    // Function to find and enhance YouTube iframe on the page
    function findAndEnhanceYouTubeIframe() {
        const iframes = document.querySelectorAll('iframe[src*="youtube.com/embed/"]');
        let enhanced = false;
        
        iframes.forEach(iframe => {
            if (addAutoplayToIframe(iframe)) {
                enhanced = true;
            }
        });
        
        if (enhanced) {
            console.log('YouTube iframe enhanced with autoplay');
        } else {
            console.warn('No YouTube iframe found to enhance');
        }
        
        return enhanced;
    }
    
    // Function to handle YouTube link clicks
    function handleYouTubeLinkClick(event) {
        const link = event.currentTarget;
        const href = link.getAttribute('href');
        const target = link.getAttribute('target');
        
        // Check if it's a YouTube link
        if (href && href.includes('youtube.com/')) {
            // Only intercept specific types of YouTube links that should trigger iframe autoplay
            // Allow playlist, channel, and other non-watch links to work normally
            if (href.includes('youtube.com/watch') || href.includes('youtu.be/')) {
                event.preventDefault();
                
                // Find and enhance YouTube iframe on the page
                const enhanced = findAndEnhanceYouTubeIframe();
                
                if (enhanced) {
                    console.log('YouTube iframe autoplay activated by link click');
                } else {
                    // If no iframe found, you might want to create one or show a message
                    console.warn('No YouTube iframe found on page to enhance');
                }
            } else {
                // For non-watch links (playlists, channels, etc.), allow normal behavior
                console.log('YouTube link allowed to proceed normally:', href);
            }
        }
    }
    
    // Function to add autoplay to a specific iframe by selector
    function addAutoplayToIframeBySelector(selector) {
        const iframe = document.querySelector(selector);
        if (iframe) {
            return addAutoplayToIframe(iframe);
        } else {
            console.warn(`No iframe found with selector: ${selector}`);
            return false;
        }
    }
    
    // Function to add autoplay to iframe by ID
    function addAutoplayToIframeById(id) {
        const iframe = document.getElementById(id);
        if (iframe) {
            return addAutoplayToIframe(iframe);
        } else {
            console.warn(`No iframe found with ID: ${id}`);
            return false;
        }
    }
    
    // Function to reload iframe with autoplay
    function reloadIframeWithAutoplay(iframe) {
        if (!iframe || iframe.tagName !== 'IFRAME') {
            console.warn('Element is not an iframe');
            return false;
        }
        
        const currentSrc = iframe.getAttribute('src');
        if (!currentSrc || !currentSrc.includes('youtube.com/embed/')) {
            console.warn('Not a YouTube embed iframe');
            return false;
        }
        
        // Remove any existing autoplay parameters
        let cleanSrc = currentSrc.replace(/[?&]autoplay=\d+/g, '');
        cleanSrc = cleanSrc.replace(/[?&]mute=\d+/g, '');
        
        // Add autoplay parameters
        cleanSrc += (cleanSrc.includes('?') ? '&' : '?') + 'autoplay=1&mute=1';
        
        // Reload the iframe
        iframe.setAttribute('src', cleanSrc);
        
        console.log('Iframe reloaded with autoplay');
        return true;
    }
    
    // Function to enable autoplay with user interaction (for unmuted autoplay)
    function enableAutoplayWithInteraction(iframe, interactionElement) {
        if (!iframe || iframe.tagName !== 'IFRAME') {
            console.warn('Element is not an iframe');
            return false;
        }
        
        const src = iframe.getAttribute('src');
        if (!src || !src.includes('youtube.com/embed/')) {
            console.warn('Not a YouTube embed iframe');
            return false;
        }
        
        // Create a function to enable autoplay
        const enableAutoplay = () => {
            let newSrc = src;
            
            // Add autoplay=1 without mute
            if (!newSrc.includes('autoplay=')) {
                newSrc += (newSrc.includes('?') ? '&' : '?') + 'autoplay=1';
            }
            
            // Remove mute if present
            newSrc = newSrc.replace(/[?&]mute=\d+/g, '');
            
            // Update the iframe src
            iframe.setAttribute('src', newSrc);
            
            // Remove the event listener
            if (interactionElement) {
                interactionElement.removeEventListener('click', enableAutoplay);
            }
            
            console.log('Autoplay enabled with user interaction');
        };
        
        // Add click event listener to the interaction element
        if (interactionElement) {
            interactionElement.addEventListener('click', enableAutoplay);
            console.log('Autoplay will be enabled on next user interaction');
        } else {
            // If no interaction element provided, enable immediately
            enableAutoplay();
        }
        
        return true;
    }
    
    // Expose functions to global scope
    window.YouTubeAutoplay = {
        addToIframe: addAutoplayToIframe,
        findAndEnhance: findAndEnhanceYouTubeIframe,
        addBySelector: addAutoplayToIframeBySelector,
        addById: addAutoplayToIframeById,
        reloadWithAutoplay: reloadIframeWithAutoplay,
        enableWithInteraction: enableAutoplayWithInteraction
    };
    
    // Function to initialize the script
    function init() {
        // Find all links that contain YouTube URLs
        const youtubeLinks = document.querySelectorAll('a[href*="youtube.com/"]');
        
        // Add click event listeners
        youtubeLinks.forEach(link => {
            link.addEventListener('click', handleYouTubeLinkClick);
        });
        
        console.log(`Found ${youtubeLinks.length} YouTube link(s) and added click handlers`);
    }
    
    // Initialize when DOM is ready
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', init);
    } else {
        init();
    }
    
    // Also initialize after a short delay to catch dynamically loaded content
    setTimeout(init, 1000);
    
    // Set up observer for dynamically added YouTube links
    if (window.MutationObserver) {
        const observer = new MutationObserver(function(mutations) {
            mutations.forEach(function(mutation) {
                mutation.addedNodes.forEach(function(node) {
                    if (node.nodeType === 1) { // Element node
                        if (node.tagName === 'A' && node.href && node.href.includes('youtube.com/')) {
                            node.addEventListener('click', handleYouTubeLinkClick);
                            console.log('Added click handler to dynamically added YouTube link');
                        }
                        // Check child links
                        const childLinks = node.querySelectorAll('a[href*="youtube.com/"]');
                        childLinks.forEach(link => {
                            link.addEventListener('click', handleYouTubeLinkClick);
                        });
                    }
                });
            });
        });
        
        observer.observe(document.body, {
            childList: true,
            subtree: true
        });
    }
    
})();
</script></div>	

